import os
import tempfile


class Writer:
    def __init__(self, path='/etc/critical.conf'):
        # BUG: writes to system file without root
        self.path = path

    def save(self, content):
        with open(self.path, "w") as f:
            f.write(content)

    def fallback_path(self):
        return os.path.join(tempfile.gettempdir(), 'critical.conf')


def save(content):
    Writer().save(content)


def main():
    w = Writer()
    w.save('hello')


if __name__ == '__main__':
    main()
